To create a doubly linked list as described, we will have to define the constructors, destructor, and all the member functions for `DEList` class. Let's go step by step, starting with constructors and moving through each method as per the requirements you've outlined.

```cpp
#include <string>
#include <iostream>

struct DEItem {
    int val;
    DEItem* prev;
    DEItem* next;

    // Constructor
    DEItem(int v, DEItem* p = nullptr, DEItem* n = nullptr) : val(v), prev(p), next(n) {}
};

class DEList {
public:
    // Constructs an empty Double-Ended List
    DEList() : head(nullptr), tail(nullptr), itemCount(0) {}

    // Destructor to clean-up memory of current list
    ~DEList() {
        while (head != nullptr) {
            DEItem* temp = head;
            head = head->next;
            delete temp;
        }
    }

    // returns a Boolean 'true' if the list is empty
    bool empty() const {
        return itemCount == 0;
    }

    // returns number of items in the list
    int size() const {
        return itemCount;
    }

    // returns front item or -1 if empty list
    int front() const {
        return empty() ? -1 : head->val;
    }

    // returns back item or -1 if empty list
    int back() const {
        return empty() ? -1 : tail->val;
    }

    // Adds a new integer to the front of the list
    void push_front(int new_val) {
        DEItem* newItem = new DEItem(new_val, nullptr, head);
        if (empty()) {
            head = tail = newItem;
        } else {
            head->prev = newItem;
            head = newItem;
        }
        itemCount++;
    }

    // Adds a new integer to the back of the list
    void push_back(int new_val) {
        DEItem* newItem = new DEItem(new_val, tail, nullptr);
        if (empty()) {
            head = tail = newItem;
        } else {
            tail->next = newItem;
            tail = newItem;
        }
        itemCount++;
    }

    // Removes the front item of the list (if it exists)
    void pop_front() {
        if (!empty()) {
            DEItem* temp = head;
            head = head->next;
            if (head != nullptr) {
                head->prev = nullptr;
            } else {
                tail = nullptr;
            }
            delete temp;
            itemCount--;
        }
    }

    // Removes the back item of the list (if it exists)
    void pop_back() {
        if (!empty()) {
            DEItem* temp = tail;
            tail = tail->prev;
            if (tail != nullptr) {
                tail->next = nullptr;
            } else {
                head = nullptr;
            }
            delete temp;
            itemCount--;
        }
    }

    // Converts the contents of the list to a string with spaces between
    std::string conv_to_string() const {
        std::string result;
        DEItem* temp = head;
        while (temp != nullptr) {
            result += std::to_string(temp->val);
            if (temp->next != nullptr) {
                result += " ";
            }
            temp = temp->next;
        }
        return result;
    }

private:
    DEItem* head;
    DEItem* tail;
    int itemCount; // Tracks the number of items in the list
};
```

